esqlQuery.esql:
// Alert when one model accounts for more than 90% of total tokens.
// Two-stage aggregation: per-model totals, then compare top model vs grand total.
// Requires at least 2 active models and minimum volume to avoid false positives.
// Adjust the 90.0 threshold in the final WHERE clause as needed.
FROM metrics-anthropic_metrics.usage-*
| WHERE anthropic.usage.uncached_input_tokens IS NOT NULL AND anthropic.usage.model IS NOT NULL
| STATS model_tokens = SUM(anthropic.usage.uncached_input_tokens) + SUM(anthropic.usage.cached_input_tokens) + SUM(anthropic.usage.output_tokens) BY anthropic.usage.model
| SORT model_tokens DESC
| LIMIT 20
| STATS top_model_tokens = MAX(model_tokens), grand_total = SUM(model_tokens), model_count = COUNT(*)
| EVAL dominance_pct = ROUND(top_model_tokens * 100.0 / grand_total, 1)
| WHERE model_count >= 2 AND grand_total > 10000 AND dominance_pct > 90.0
